import React, { useEffect } from "react";
import { Connection, PublicKey, Transaction } from "@solana/web3.js";
import "./JupiterModal.css";
// Wallet
import { useWallet, useConnection } from "@solana/wallet-adapter-react";

// Store
import useUserSOLBalanceStore from "../../../stores/useUserSOLBalanceStore";

export const JupiterModal = () => {
  const wallet = useWallet();
  const { connection } = useConnection();

  const balance = useUserSOLBalanceStore((s) => s.balance);
  const { getUserSOLBalance } = useUserSOLBalanceStore();

  useEffect(() => {
    if (wallet.publicKey) {
      console.log(wallet.publicKey.toBase58());
      getUserSOLBalance(wallet.publicKey, connection);
    }
  }, [wallet.publicKey, connection, getUserSOLBalance]);

  useEffect(() => {
    window.Jupiter.init({
      displayMode: "integrated",
      integratedTargetId: "integrated-terminal",
      // endpoint: "https://api.mainnet-beta.solana.com",
      endpoint:
        "https://rpc.helius.xyz/?api-key=7d2040bc-1d8b-4db9-a9f3-534568617037",
      formProps: {
        initialOutputMint: "AgnHzGspNu7F3nFM4izuPt5g7m1URjVaTaFNgvqSXcjC",
        initialInputMint: "So11111111111111111111111111111111111111112",
      },
    });

    // Define a function to insert the "BUY" string
    const insertBuyParagraph = () => {
      // Select the specific element
      const targetAnchor = document.querySelector(
        "#jupiter-terminal a.flex.items-center.space-x-2"
      );
      if (targetAnchor) {
        // Insert "BUY" after the anchor element
        targetAnchor.insertAdjacentHTML(
          "afterend",
          `
          <p class="hidden md:block !font-BenzinBold text-neutral-orange md:text-3xl relative md:bottom-[20px]">BUY $NCTR</p>
        `
        );
        return true; // Indicate that the element was found and modified
      }
      return false; // Indicate that the element was not found
    };

    // Set an interval to periodically check for the element
    const intervalId = setInterval(() => {
      const isInserted = insertBuyParagraph();
      if (isInserted) {
        clearInterval(intervalId); // Clear the interval once the paragraph is inserted
      }
    }, 100); // Check every 100 milliseconds

    // Clean up the interval on component unmount
    return () => clearInterval(intervalId);
  }, []);

  return (
    <div className="w-full bg-background-grayPrimary rounded-xl ">
      <div id="integrated-terminal"></div>
    </div>
  );
};
